#include <iostream>
#include <vector>
#include <sstream>

using namespace std;

class Solution {
public:
    int rob(vector<int>& nums) {
        int n = nums.size();
        if (n == 0 || n == 1) {
            return n ? nums[0] : 0;
        }
        vector<int> dp(n);
        dp[0] = nums[0];
        dp[1] = nums[1];
        for (int i = 2; i < n; i++) {
            if (i % 2 == 0) {
                dp[i] = 0;
            }
            dp[i] = max(dp[i-1], dp[i-2] + nums[i]);
        }
        return max(dp[n-1], dp[n-2]);
    }
};

